import type { Node } from '@antv/x6'
import type { MenuItem } from './types'
import type { ModeCapabilities } from '../../../views/types/flow.types'
import {
  GroupOutlined,
  UngroupOutlined,
  CopyOutlined,
  SnippetsOutlined,
  VerticalAlignTopOutlined,
  VerticalAlignBottomOutlined,
  DeleteOutlined,
} from '@ant-design/icons-vue'

/**
 * 节点右键菜单配置
 */
export function useNodeMenu() {
  /**
   * 获取节点菜单项
   * @param node 节点对象
   * @param isGroup 是否为组节点
   * @param isMultiSelect 是否多选
   * @param capabilities 模式权限
   */
  function getNodeMenuItems(
    node: Node,
    isGroup: boolean,
    isMultiSelect: boolean,
    capabilities: ModeCapabilities
  ): MenuItem[] {
    const items: MenuItem[] = []

    // 多选时显示成组选项（仅设计模式）
    if (isMultiSelect && capabilities.canGroup) {
      items.push(
        { key: 'group', label: '成组 (Ctrl+G)', icon: GroupOutlined },
        { key: 'div1', divider: true }
      )
    }

    // 组节点显示解组选项（仅设计模式）
    if (isGroup && capabilities.canGroup) {
      items.push(
        { key: 'ungroup', label: '解组 (Ctrl+Shift+G)', icon: UngroupOutlined },
        { key: 'div1', divider: true }
      )
    }

    // 复制操作（仅设计模式）
    if (capabilities.canCopy) {
      items.push(
        { key: 'copy', label: '复制节点 (Ctrl+C)', icon: CopyOutlined }
      )
    }

    // 粘贴操作（仅设计模式）
    if (capabilities.canPaste) {
      items.push(
        { key: 'paste', label: '粘贴节点 (Ctrl+V)', icon: SnippetsOutlined }
      )
    }

    // 如果有复制或粘贴，添加分割线
    if (capabilities.canCopy || capabilities.canPaste) {
      items.push({ key: 'div2', divider: true })
    }

    // 层级调整
    if (capabilities.canToFront || capabilities.canToBack) {
      if (capabilities.canToFront) {
        items.push(
          { key: 'toFront', label: '层级前置', icon: VerticalAlignTopOutlined },
        )
      }
      if (capabilities.canToBack) {
        items.push(
          { key: 'toBack', label: '层级后置', icon: VerticalAlignBottomOutlined },
        )
      }
      items.push({ key: 'div3', divider: true })
    }

    // 删除操作（仅设计模式）
    if (capabilities.canDelete) {
      items.push(
        { key: 'delete', label: '删除节点 (Delete)', icon: DeleteOutlined, danger: true }
      )
    }

    return items
  }

  return {
    getNodeMenuItems
  }
}
