import type { DesignerMode, ModeCapabilities } from '../../../views/types/flow.types'
import {
  builtinPermissionPresets,
  resolvePermissions,
  type PermissionOptions,
} from '../types/permissions'

/**
 * 模式管理器
 * 管理设计器的工作模式及对应的权限
 * 支持从外部传入自定义权限配置
 */
export class ModeManager {
  private currentMode: string = 'design'
  private permissionOptions: PermissionOptions = {}
  private cachedCapabilities: ModeCapabilities | null = null

    /**
   * 构造函数
   * @param options 权限选项
   */
  constructor(options: PermissionOptions = {}) {
    this.permissionOptions = options
    this.currentMode = options.mode || 'design'
  }

  // ─── 配置更新 ───────────────────────────────────────────────────────────────

  /**
   * 更新权限选项（用于运行时动态修改）
   */
  updatePermissionOptions(options: Partial<PermissionOptions>): void {
    this.permissionOptions = {
      ...this.permissionOptions,
      ...options,
    }
    this.cachedCapabilities = null // 清除缓存
  }

  // ─── 模式操作 ───────────────────────────────────────────────────────────────

  getMode(): string {
    return this.currentMode
  }

  setMode(mode: string): void {
    if (this.currentMode !== mode) {
      this.currentMode = mode
      this.cachedCapabilities = null // 清除缓存
    }
  }

  /**
   * 获取当前模式的权限配置
   * 会根据传入的 permissionOptions 自动合并
   */
  getCapabilities(): ModeCapabilities {
    if (!this.cachedCapabilities) {
      this.cachedCapabilities = resolvePermissions(this.currentMode, {
        ...this.permissionOptions,
        mode: this.currentMode,
      })
    }
    return { ...this.cachedCapabilities }
  }

    // ─── 模式判断 ───────────────────────────────────────────────────────────────

  /**
   * 判断当前是否为指定模式
   */
  isMode(mode: string): boolean {
    return this.currentMode === mode
  }

  isDesignMode(): boolean {
    return this.currentMode === 'design'
  }

  isReadonlyMode(): boolean {
    return this.currentMode === 'readonly'
  }

  isPreviewMode(): boolean {
    return this.currentMode === 'preview'
  }

    // ─── 权限检查 ───────────────────────────────────────────────────────────────

  /**
   * 检查当前模式是否具有某项权限
   */
  can(capability: keyof ModeCapabilities): boolean {
    return this.getCapabilities()[capability]
  }

  /**
   * 批量检查多个权限（AND 逻辑）
   */
  canAll(...capabilities: Array<keyof ModeCapabilities>): boolean {
    const current = this.getCapabilities()
    return capabilities.every((cap) => current[cap])
  }

  /**
   * 批量检查多个权限（OR 逻辑）
   */
  canAny(...capabilities: Array<keyof ModeCapabilities>): boolean {
    const current = this.getCapabilities()
    return capabilities.some((cap) => current[cap])
  }

  // ─── 序列化 ─────────────────────────────────────────────────────────────────

  toJSON() {
    return {
      mode: this.currentMode,
      capabilities: this.getCapabilities(),
    }
  }
}
