import type { Edge } from '@antv/x6'
import type { MenuItem } from './types'
import type { ModeCapabilities } from '../../../views/types/flow.types'
import { DisconnectOutlined } from '@ant-design/icons-vue'

/**
 * 连线右键菜单配置
 */
export function useEdgeMenu() {
  /**
   * 获取连线菜单项
   * @param edge 连线对象
   * @param capabilities 模式权限
   */
  function getEdgeMenuItems(edge: Edge, capabilities: ModeCapabilities): MenuItem[] {
    const items: MenuItem[] = []

    // 删除连线（仅设计模式）
    if (capabilities.canDelete) {
      items.push(
        { key: 'delete', label: '删除连线 (Delete)', icon: DisconnectOutlined, danger: true }
      )
    }

    return items
  }

  return {
    getEdgeMenuItems
  }
}
