            :has-selection="scope.hasSelection"
            :can-paste="scope.canPaste"
            :can-group="scope.canGroup"
            :can-ungroup="scope.canUngroup"
            :can-undo="scope.canUndo"
            :can-redo="scope.canRedo"
            :designer-mode="scope.currentMode"
            @undo="scope.onUndo"
            @redo="scope.onRedo"
