  message.error(`错误: ${error.message}`)
}

// ─── mode-change 事件 ─────────────────────────────────────────────────────────
function handleModeChange(mode: DesignerMode) {
  message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)
  currentMode.value = mode
}

// ─── 从 ModeSelection 组件触发的模式切换 ─────────────────────────────────────
function handleModeChangeFromSelector(mode: DesignerMode) {
  // 🎯 调用 designer.setMode() 更新 designer 内部状态
  if (designer.value) {
    console.log('[FlowDesignerTest] 调用 designer.setMode()', mode)
    designer.value.setMode(mode)
  } else {
    console.warn('[FlowDesignerTest] designer 实例不存在，无法切换模式')
  }

  // 更新本地状态（保持同步）
  currentMode.value = mode

  //message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)
}

// ─── 节点添加前拦截器 ──────────────────────────────────────────────────────────
/**
 * 节点添加前拦截示例：
 * 1. 验证节点类型是否允许添加
 * 2. 检查节点数量限制
 * 3. 可修改节点属性（如位置、样式）
 * 4. 调用 preventDefault() 阻止添加
 */
function handleBeforeNodeAdd(event: BeforeNodeAddEvent): boolean {
  const { node, source } = event
  const nodeData = node.getData()

  console.log('[Before Node Add]', {
    nodeId: node.id,
    nodeType: nodeData?.type,
    source,
    position: node.getPosition(),
  })
  // 示例1：限制 start-node 类型节点只能添加一个
  if (node.shape === 'start-node') {
    const designer = layoutRef.value?.designer
    if (designer) {
      const graph = designer.getGraph()
      const existingStartNodes = graph.getNodes().filter(n => {
        return n?.shape === 'start-node'
      })

      if (existingStartNodes.length > 0) {
        message.warning('开始节点只能添加一个！')
        return false // 返回 false 阻止添加
      }
    }
  }

  // 示例2：自动吸附到网格（20px）
  const pos = node.getPosition()
  const snappedX = Math.round(pos.x / 20) * 20
  const snappedY = Math.round(pos.y / 20) * 20
  if (pos.x !== snappedX || pos.y !== snappedY) {
    // ✅ 使用 silent: true 避免触发 change:position 事件
    // beforeNodeAdd 是预处理阶段,修改应该是静默的,不应产生独立的历史记录
    node.setPosition({ x: snappedX, y: snappedY }, { silent: true })
    console.log('[Before Node Add] 位置已吸附到网格:', { x: snappedX, y: snappedY })
  }

  // 示例3：根据来源添加自定义标记
  if (source === 'paste') {
    const currentData = node.getData() || {}
    // ✅ 使用 silent: true 避免触发 change:data 事件
    node.setData({
      ...currentData,
      _pastedAt: Date.now(),
    }, { silent: true })
    console.log('[Before Node Add] 已标记粘贴时间')
  }

  return true // 返回 true 允许添加
}

// ─── 节点添加后回调 ────────────────────────────────────────────────────────────
/**
 * 节点添加后通知示例：
 * 1. 记录操作日志
 * 2. 更新统计数据
 * 3. 同步到外部系统
 */
function handleAfterNodeAdd(event: AfterNodeAddEvent) {
  const { nodeId, source, success, timestamp } = event

  if (success) {
    console.log('[After Node Add] 节点添加成功', {
      nodeId,
      source,
      timestamp: new Date(timestamp).toLocaleTimeString(),
    })

    // ── common-vue-node：从 data.nodeType 读取类型并写入 node prop ──────────
    // NodePalette 拖入时在 data 里携带了 nodeType 字段，这里转存到 X6 prop
    const graph = layoutRef.value?.designer?.getGraph()
    const node = graph?.getCellById(nodeId)
    if (node?.isNode() && node.shape === 'common-vue-node') {
      const nodeType = node.getData()?.nodeType
      if (nodeType) {
        node.setProp('node-type', nodeType)
      }
    }

    // 示例：显示通知（仅非撤销/重做操作）
    if (source !== 'undo' && source !== 'redo') {
      message.success(`节点已添加（来源: ${source}）`, 2)
    }
  } else {
    console.error('[After Node Add] 节点添加失败', event.error)
  }
}

/**
 * 节点删除前拦截示例：
 * 1. 禁止删除特定类型的节点（如结束节点）
 * 2. 删除前确认
 * 3. 根据来源显示不同提示
 */
function handleBeforeNodeRemove(event: BeforeNodeRemoveEvent): boolean {
  const { node, source } = event

  console.log('[Before Node Remove]', {
    nodeId: node.id,
    nodeShape: node.shape,
    source,
  })

  // 示例1：禁止删除结束节点
  if (node.shape === 'end-node') {
    message.warning('结束节点不能删除！')
    return false // 返回 false 阻止删除
  }

  // 示例2：开始节点删除前确认
  if (node.shape === 'start-node' && source === 'keyboard') {
    // 注意：这里只是演示，实际生产环境中不建议在拦截器中使用同步 confirm
    // 应该使用 Modal.confirm 等异步确认方式
    message.info(`正在删除开始节点（来源: ${source}）`)
  }

  // 示例3：批量删除时的提示
  if (source === 'clear') {
    console.log('[Before Node Remove] 画布清空操作，节点将被删除:', node.id)
  }

  return true // 返回 true 允许删除
}

// ─── 连线创建前拦截器 ──────────────────────────────────────────────────────────
/**
 * 连线创建前拦截示例（在 validateConnection 阶段触发）：
 * sourceCell/targetCell 均已知，可做完整的双端规则校验
 * 调用 preventDefault() 阻止连线创建
 */
function handleBeforeEdgeAdd(event: BeforeEdgeAddEvent): boolean {
  const { sourceCell, targetCell, sourceMagnet, targetMagnet } = event

  console.log('[Before Edge Add] validateConnection 阶段拦截', {
    sourceCellId: sourceCell.id,
    sourceCellShape: (sourceCell as any).shape,
    targetCellId: targetCell.id,
    targetCellShape: (targetCell as any).shape,
  });

  // 基础规则验证
  // const srcGroup = sourceMagnet?.getAttribute('port-group') ?? ''
  // const tgtGroup = targetMagnet?.getAttribute('port-group') ?? ''
  // const validSrc = ['out', 'right', 'bottom', 'left'].includes(srcGroup)
  // if (!validSrc || !sourceMagnet) return false;
  // if (tgtGroup !== 'in' || !targetMagnet) return false;
  // if ((targetCell as any)?.shape === 'start-node') return false;
  // if ((sourceCell as any)?.shape === 'end-node') return false;
  // if (sourceCell === targetCell) return false;

  const designer = layoutRef.value?.designer
  if (!designer) return true

  const graph = designer.getGraph()

  // 示例1：禁止特定节点类型互连（条件节点 → 开始节点）
  if ((sourceCell as any).shape === 'condition-node' && (targetCell as any).shape === 'start-node') {
    message.warning('条件节点不能连接到开始节点！')
    return false // 返回 false 阻止连接
  }

  // 示例2：限制单个节点最多3条出度
  const sourceEdges = graph.getConnectedEdges(sourceCell, { outgoing: true })
  if (sourceEdges.length >= 3) {
    message.warning('单个节点最多只能连接3条出线！')
    return false
  }

  // 示例3：限制单个节点最多2条入度
  const targetEdges = graph.getConnectedEdges(targetCell, { incoming: true })
  if (targetEdges.length >= 2) {
    message.warning('单个节点最多只能接收2条入线！')
    return false
  }

  // 示例4：检测双向连线（A→B 后禁止 B→A）
  const hasReverse = graph.getEdges().some(e => {
    return e.getSourceCell()?.id === targetCell.id && e.getTargetCell()?.id === sourceCell.id
  })
  if (hasReverse) {
    message.warning('不允许创建双向连线！')
    return false
  }

  console.log('[Before Edge Add] 验证通过，允许创建连线')
  return true // 返回 true 允许连接
}

// ─── 连线添加后回调 ────────────────────────────────────────────────────────────
/**
 * 连线添加后通知示例：
 * 1. 记录连线日志
 * 2. 更新流程统计
 * 3. 同步到外部系统
 */
function handleAfterEdgeAdd(event: AfterEdgeAddEvent) {
  const { edgeId, sourceNodeId, targetNodeId, sourceAction, success, timestamp } = event

  if (success) {
    console.log('[After Edge Add] 连线创建成功', {
      edgeId,
      sourceNodeId,
      targetNodeId,
      sourceAction,
      timestamp: new Date(timestamp).toLocaleTimeString(),
    })

    // 示例：显示通知（仅非撤销/重做操作）
    if (sourceAction !== 'undo' && sourceAction !== 'redo') {
      message.success(`连线已创建（来源: ${sourceAction}）`, 2)
    }
  } else {
    console.error('[After Edge Add] 连线创建失败', event.error)
    message.error('连线创建失败！')
  }
}

// ─── 连线删除前拦截器 ──────────────────────────────────────────────────────────
/**
 * 连线删除前拦截示例：
 * 1. 禁止删除特定连线（如关键路径上的连线）
 * 2. 根据来源显示不同提示
 * 3. 调用 preventDefault() 阻止删除
 */
function handleBeforeEdgeRemove(event: BeforeEdgeRemoveEvent): boolean {
  const { edge, edgeId, sourceNodeId, targetNodeId, source } = event

  console.log('[Before Edge Remove]', {
    edgeId,
    sourceNodeId,
    targetNodeId,
    source,
  })

  // 示例1：禁止删除带有 locked 标记的连线
  const edgeData = edge.getData()
  if (edgeData?.locked) {
    message.warning('该连线已被锁定，不允许删除！')
    return false // 返回 false 阻止删除
  }

  // 示例2：清空画布时记录日志，不阻止
  if (source === 'clear') {
    console.log('[Before Edge Remove] 画布清空操作，连线将被删除:', edgeId)
  }

  return true // 返回 true 允许删除
}

// ─── 连线删除后回调 ────────────────────────────────────────────────────────────
/**
 * 连线删除后通知示例：
 * 1. 记录删除日志
 * 2. 同步到外部系统
 */
function handleAfterEdgeRemove(event: AfterEdgeRemoveEvent) {
  const { edgeId, sourceNodeId, targetNodeId, source } = event

  console.log('[After Edge Remove] 连线已删除', {
    edgeId,
    sourceNodeId,
    targetNodeId,
    source,
  })

  // 示例：显示通知（仅非撤销/重做操作）
  if (source !== 'undo' && source !== 'redo') {
    message.info(`连线已删除（来源: ${source}）`, 2)
  }
}

// ─── 数据加载完成事件 ─────────────────────────────────────────────────────────
/**
 * afterDataLoaded：数据加载完成后，居中显示顶层起始节点（入度为 0 的节点）
 */
function handleAfterDataLoaded(data: FlowData) {
  console.log('[After Data Loaded] 画布数据加载完成，节点数:', data.nodes?.length ?? 0)
  const designer = layoutRef.value?.designer
  if (!designer) return
  // 获取顶层起始节点（入度为 0）
  const rootNodes = designer.getRootNodes()
  if (rootNodes.length > 0) {
    //layoutRef.value?.centerNode(rootNodes[0].id)
    //console.log('[After Data Loaded] 已居中显示顶层节点:', rootNodes[0].id)
  } else {
    console.log('[After Data Loaded] 未找到顶层节点')
  }
}

defineExpose({ layoutRef })
