import { Graph, Node } from '@antv/x6'
import type { CanvasConfigManager } from './CanvasConfigManager'
import type { ModeManager } from './ModeManager'
import type { CanvasConfig } from '../../../views/types/flow.types'

// ─── 类型定义 ───────────────────────────────────────────────────────────────

/** 节点状态上下文（传递给状态处理器） */
export interface NodeStateContext {
  config: CanvasConfig
  graph: Graph
  manager: NodeStateManager
  canConnect: boolean  // 是否允许连线（影响锚点显示）
}

/** 节点状态处理器接口 */
export interface NodeStateHandler {
  /**
   * 应用状态样式
   * @param node 目标节点
   * @param context 上下文（包含 config、graph、manager、canConnect）
   */
  apply(node: Node, context: NodeStateContext): void

  /**
   * 清理状态（可选，离开状态时调用）
   * @param node 目标节点
   * @param context 上下文
   */
  cleanup?(node: Node, context: NodeStateContext): void
}

/** 节点状态类型 */
export type NodeState = 'default' | 'selected' | 'hover' | 'dragging' | string

// ─── 配置选项 ───────────────────────────────────────────────────────────────

export interface NodeStateManagerOptions {
  graph: Graph
  config: CanvasConfigManager
  mode: ModeManager
  tooltipEl?: HTMLElement | null
  /**
   * 获取回调函数的 getter，动态获取最新的回调引用
   */
  getCallbacks?: () => {
    onTooltipChange?: (payload: any) => void
  }
}

/**
 * NodeStateManager 节点状态管理器
 *
 * 职责：
 * - 管理节点的状态（default、hover、selected、dragging等）
 * - 管理节点的锚点显示和样式
 * - 管理节点的 Tooltip 显示和位置
 * - 提供节点状态处理器的注册/获取/移除 API
 */
export class NodeStateManager {
  private graph: Graph
  private config: CanvasConfigManager
  private mode: ModeManager
  private tooltipEl: HTMLElement | null
  private getCallbacks: () => {
    onTooltipChange?: (payload: any) => void
  }

  // 状态处理器注册表（策略模式）
  private stateHandlers: Map<string, NodeStateHandler> = new Map()

  // hover 状态追踪
  private hoveredNodeId: string | null = null

  // 拖拽状态追踪
  private draggingNodeId: string | null = null

  constructor(options: NodeStateManagerOptions) {
    this.graph = options.graph
    this.config = options.config
    this.mode = options.mode
    this.tooltipEl = options.tooltipEl || null
    this.getCallbacks = options.getCallbacks || (() => ({}))

    // 注册内置状态处理器
    this.registerBuiltInHandlers()
  }

  // ─── 状态管理 API ───────────────────────────────────────────────────────────

  /**
   * 设置节点状态：使用策略模式调用注册的状态处理器
   * @param node  目标节点
   * @param state 状态名称（default | selected | hover | dragging | 自定义状态）
   */
  public setNodeState(node: Node, state: string): void {
    // 1. 从 prop 读取当前状态（不污染业务 data）
    const prevState = node.getProp('_state') ?? 'default'

    // 2. 只有在状态真正切换时，才调用旧状态的 cleanup
    if (prevState !== state) {
      const prevHandler = this.stateHandlers.get(prevState)
      if (prevHandler?.cleanup) {
        try {
          prevHandler.cleanup(node, this.getStateContext())
        } catch (error) {
          console.error(`[NodeStateManager] Error cleaning up state "${prevState}":`, error)
        }
      }
    }

    // 3. 更新状态到 prop（不使用 silent: true 确保事件监听成功）
    node.setProp('_state', state)

    // 4. 调用新状态的 apply
    const handler = this.stateHandlers.get(state)
    if (!handler) {
      console.warn(`[NodeStateManager] Unknown node state: "${state}", available states:`, this.getRegisteredStates())
      return
    }

    try {
      handler.apply(node, this.getStateContext())
    } catch (error) {
      console.error(`[NodeStateManager] Error applying state "${state}":`, error)
    }
  }

  /**
   * 重置所有节点为 default 状态（可排除指定节点）
   */
  public resetAllNodes(exceptId?: string): void {
    this.graph.getNodes().forEach((node) => {
      if (node.id !== exceptId) {
        this.setNodeState(node, 'default')
      }
    })
  }

  /**
   * 获取节点状态上下文
   */
  public getStateContext(): NodeStateContext {
    return {
      config: this.config.getConfig(),
      graph: this.graph,
      manager: this,
      canConnect: this.mode.can('canConnect'),
    }
  }

  // ─── 锚点（Port）管理 ───────────────────────────────────────────────────────

  /**
   * 设置节点锚点可见性和样式
   * @param node 目标节点
   * @param visible 是否可见
   * @param style 'default' | 'hover'（当 visible=true 时有效）
   */
  public setPortsVisibility(node: Node, visible: boolean, style: 'default' | 'hover' = 'default'): void {
    const config = this.config.getConfig()
    const canConnect = this.mode.can('canConnect')

    if (!canConnect) return

    node.getPorts().forEach((p) => {
      if (!p.id) return

      // 设置可见性
      node.setPortProp(p.id, ['attrs', 'circle', 'style', 'visibility'], visible ? 'visible' : 'hidden')

      // 如果可见，设置样式
      if (visible) {
        const portConfig = style === 'hover'
          ? config.highlight.portHover
          : config.highlight.portDefault

        node.setPortProp(p.id, ['attrs', 'circle', 'stroke'], portConfig.strokeColor || portConfig.stroke)
        node.setPortProp(p.id, ['attrs', 'circle', 'r'], portConfig.size)
        node.setPortProp(p.id, ['attrs', 'circle', 'fill'], portConfig.fillColor || portConfig.fill)
        node.setPortProp(p.id, ['attrs', 'circle', 'strokeWidth'], portConfig.strokeWidth)
      }
    })
  }

  /**
   * 设置单个锚点的 hover 样式
   */
  public setPortHoverStyle(node: Node, portId: string): void {
    const config = this.config.getConfig()
    const portConfig = config.highlight.portHover

    if (!portConfig.enabled) return

    node.setPortProp(portId, ['attrs', 'circle', 'fill'], portConfig.fillColor)
    node.setPortProp(portId, ['attrs', 'circle', 'stroke'], portConfig.strokeColor)
    node.setPortProp(portId, ['attrs', 'circle', 'r'], portConfig.size)
    node.setPortProp(portId, ['attrs', 'circle', 'strokeWidth'], portConfig.strokeWidth)
  }

  /**
   * 恢复单个锚点的默认样式
   */
  public resetPortStyle(node: Node, portId: string): void {
    const config = this.config.getConfig()
    const portConfig = config.highlight.portDefault

    node.setPortProp(portId, ['attrs', 'circle', 'stroke'], portConfig.stroke)
    node.setPortProp(portId, ['attrs', 'circle', 'r'], portConfig.size)
    node.setPortProp(portId, ['attrs', 'circle', 'fill'], portConfig.fill)
    node.setPortProp(portId, ['attrs', 'circle', 'strokeWidth'], portConfig.strokeWidth)
  }

  // ─── Tooltip 管理 ───────────────────────────────────────────────────────────

  /**
   * 显示节点 Tooltip
   */
  public showTooltip(node: Node, mouseEvent?: any): void {
    // 权限检查：如果不允许显示节点 tooltip，直接返回
    if (!this.mode.can('canNodeTooltip')) return

    const el = this.tooltipEl
    if (!el) return

    el.style.display = 'block'

    // 触发回调
    const callbacks = this.getCallbacks()
    callbacks.onTooltipChange?.({
      visible: true,
      type: 'node',
      node: node,
      edge: null,
      data: node.getData()
    })

    requestAnimationFrame(() => {
      const contentEl = el.querySelector('[data-role="tooltip-content"]')
      //兼容2种模式
      if (contentEl) {
        contentEl.innerHTML = node.getProp('label') || (node.getLabel?node.getLabel():'')  || (node.getData()?.label ?? '')
      }
      this.updateTooltipPosition(node)
    })
  }

  /**
   * 隐藏 Tooltip
   */
  public hideTooltip(): void {
    const el = this.tooltipEl
    if (!el) return

    el.style.left = '0px'
    el.style.top = '0px'
    el.style.display = 'none'

    // 触发回调
    const callbacks = this.getCallbacks()
    callbacks.onTooltipChange?.({
      visible: false,
      type: null,
      node: null,
      edge: null,
      data: null
    })
  }

  /**
   * 更新 Tooltip 位置（根据节点当前坐标计算）
   */
  public updateTooltipPosition(node: Node): void {
    const el = this.tooltipEl
    if (!el || el.style.display === 'none') return

    const nodePos = node.position()
    const nodePos2 = this.graph.localToPage(nodePos.x, nodePos.y)
    const zoom = this.graph.zoom()
    const nodeSize = {
      width: node.size().width * zoom,
      height: node.size().height * zoom
    }
    const zoomLevel = Math.max(1, zoom)

    // 获取 tooltip 偏移量配置
    const tooltipConfig = this.config.getConfig().tooltip
    const offsetX = tooltipConfig?.offsetX ?? 0
    const offsetY = tooltipConfig?.offsetY ?? 0

    el.style.transform = `scale(${zoomLevel})`
    el.style.transformOrigin = 'center bottom'
    el.style.left = nodePos2.x + nodeSize.width / 2 - el.clientWidth / 2 + offsetX + 'px'
    el.style.top = nodePos2.y - 50 + offsetY + 'px'
  }

  // ─── Hover 状态追踪 ─────────────────────────────────────────────────────────

  /**
   * 设置当前 hover 的节点 ID
   */
  public setHoveredNode(nodeId: string | null): void {
    this.hoveredNodeId = nodeId
  }

  /**
   * 获取当前 hover 的节点 ID
   */
  public getHoveredNode(): string | null {
    return this.hoveredNodeId
  }

  // ─── 拖拽状态追踪 ───────────────────────────────────────────────────────────

  /**
   * 设置当前拖拽的节点 ID
   */
  public setDraggingNode(nodeId: string | null): void {
    this.draggingNodeId = nodeId
  }

  /**
   * 获取当前拖拽的节点 ID
   */
  public getDraggingNode(): string | null {
    return this.draggingNodeId
  }

  // ─── 状态处理器注册 ─────────────────────────────────────────────────────────

  /**
   * 注册或覆盖节点状态处理器（公共 API）
   */
  public registerStateHandler(
    stateName: string,
    handler: NodeStateHandler,
    override = true
  ): void {
    if (!override && this.stateHandlers.has(stateName)) {
      throw new Error(`[NodeStateManager] State "${stateName}" already exists. Use override=true to replace.`)
    }
    this.stateHandlers.set(stateName, handler)
    console.log(`[NodeStateManager] Registered node state handler: "${stateName}"`)
  }

  /**
   * 获取已注册的状态处理器
   */
  public getStateHandler(stateName: string): NodeStateHandler | undefined {
    return this.stateHandlers.get(stateName)
  }

  /**
   * 移除状态处理器
   */
  public unregisterStateHandler(stateName: string): boolean {
    const result = this.stateHandlers.delete(stateName)
    if (result) {
      console.log(`[NodeStateManager] Unregistered node state handler: "${stateName}"`)
    }
    return result
  }

  /**
   * 获取所有已注册的状态名称
   */
  public getRegisteredStates(): string[] {
    return Array.from(this.stateHandlers.keys())
  }

  /**
   * 注册内置节点状态处理器
   * @private
   */
  private registerBuiltInHandlers(): void {
    // ────────────────────────────────────────────────────────────────
    // default 状态：隐藏锚点
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('default', {
      apply: (node, ctx) => {
        ctx.manager.setPortsVisibility(node, false)
      },
    })

    // ────────────────────────────────────────────────────────────────
    // hover 状态：显示锚点（如果允许连线）
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('hover', {
      apply: (node, ctx) => {
        if (ctx.canConnect) {
          ctx.manager.setPortsVisibility(node, true, 'default')
        }
      },
    })

    // ────────────────────────────────────────────────────────────────
    // selected 状态：显示锚点（如果允许连线）
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('selected', {
      apply: (node, ctx) => {
        if (ctx.canConnect) {
          ctx.manager.setPortsVisibility(node, true, 'default')
        }
      },
    })

    // ────────────────────────────────────────────────────────────────
    // dragging 状态：保持锚点可见（如果允许连线）
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('dragging', {
      apply: (node, ctx) => {
        if (ctx.canConnect) {
          ctx.manager.setPortsVisibility(node, true, 'default')
        }
      },
    })
  }

  // ─── 清理 ───────────────────────────────────────────────────────────────────

  /**
   * 销毁时清理资源
   */
  public dispose(): void {
    this.stateHandlers.clear()
    this.hoveredNodeId = null
    this.draggingNodeId = null
  }
}
