import type { Graph } from '@antv/x6'
import { Transform } from '@antv/x6'
import type { CanvasConfig, ModeCapabilities } from '../../../views/types/flow.types'
import { DEFAULT_CANVAS_CONFIG } from './defaultConfig'

/**
 * 画布配置管理器
 * 负责管理画布配置并应用到 X6 Graph
 */
export class CanvasConfigManager {
  private config: CanvasConfig

  constructor(initialConfig?: Partial<CanvasConfig>) {
    this.config = this.mergeConfig(DEFAULT_CANVAS_CONFIG, initialConfig)
  }

  // ─── 配置操作 ───────────────────────────────────────────────────────────────

  getConfig(): CanvasConfig {
    return JSON.parse(JSON.stringify(this.config))
  }

  updateConfig(update: Partial<CanvasConfig>): void {
    this.config = this.mergeConfig(this.config, update)
  }

  resetConfig(): void {
    this.config = JSON.parse(JSON.stringify(DEFAULT_CANVAS_CONFIG))
  }

  // ─── 应用配置到 Graph ───────────────────────────────────────────────────────

  applyToGraph(graph: Graph, transform?: Transform | null, capabilities?: ModeCapabilities): void {
    this.applyGridConfig(graph)
    this.applyBackgroundConfig(graph)
    this.applyConnectionConfig(graph)
    this.applyInteractionConfig(graph, transform, capabilities)
  }

  // ─── 应用网格配置 ───────────────────────────────────────────────────────────

  private applyGridConfig(graph: Graph): void {
    const { visible, type, size, color, thickness } = this.config.grid

    if (visible) {
      graph.drawGrid({
        type,
        args: {
          color,
          thickness,
        },
      })
      graph.setGridSize(size)
      graph.showGrid()
    } else {
      graph.hideGrid()
    }
  }

  // ─── 应用背景配置 ───────────────────────────────────────────────────────────

  private applyBackgroundConfig(graph: Graph): void {
    graph.drawBackground(this.config.background)
  }

  // ─── 应用连线配置 ───────────────────────────────────────────────────────────

  private applyConnectionConfig(graph: Graph): void {
    const cfg = this.config.connection

    // 更新连接配置
    if (graph.options.connecting) {
      graph.options.connecting = {
        ...graph.options.connecting,
        router: { name: cfg.router, args: { padding: 20 } },
        connector: {
          name: cfg.connector,
          args: cfg.connector === 'jumpover' ? { radius: 8 } : {}
        },
        allowBlank: cfg.allowBlank,
        allowLoop: cfg.allowLoop,
        allowMulti: cfg.allowMulti,
      }
    }

    // 更新默认边样式
    if (graph.options.defaultEdge?.attrs?.line) {
      graph.options.defaultEdge.attrs.line.stroke = cfg.strokeColor
      graph.options.defaultEdge.attrs.line.strokeWidth = cfg.strokeWidth
    }

    // 更新默认标签样式
    if (graph.options.defaultEdge?.label) {
      const labelCfg = cfg.label
      const padding = labelCfg.padding ?? 8
      const paddingPercent = 100 + (padding * 5)
      const offsetPercent = -(padding * 2.5)

      graph.options.defaultEdge.label = {
        attrs: {
          body: {
            fill: labelCfg.backgroundColor,
            stroke: labelCfg.borderColor,
            strokeWidth: labelCfg.borderWidth,
            rx: labelCfg.borderRadius,
            ry: labelCfg.borderRadius,
            refWidth: `${paddingPercent}%`,
            refHeight: `${paddingPercent}%`,
            refX: `${offsetPercent}%`,
            refY: `${offsetPercent}%`,
            filter: {
              name: 'dropShadow',
              args: { dx: 0, dy: 1, stdDeviation: 2, color: 'rgba(0,0,0,0.10)' },
            },
          },
          text: {
            fill: labelCfg.textColor,
            fontSize: labelCfg.fontSize,
            fontWeight: labelCfg.fontWeight,
            textAnchor: labelCfg.textAnchor,
            textVerticalAnchor: labelCfg.textVerticalAnchor,
            pointerEvents: labelCfg.pointerEvents,
          },
        },
        position: { distance: labelCfg.position },
      }
    }

    // 实时更新所有现有连线的样式
    const edges = graph.getEdges()
    edges.forEach(edge => {
      // 保存现有的动画属性
      const currentDasharray = edge.attr('line/strokeDasharray')
      const currentStyle = edge.attr('line/style')

      // 更新连线样式
      edge.attr('line/stroke', cfg.strokeColor)
      edge.attr('line/strokeWidth', cfg.strokeWidth)

      // 恢复动画属性（如果存在）
      if (currentDasharray) {
        edge.attr('line/strokeDasharray', currentDasharray)
      }
      if (currentStyle?.animation) {
        edge.attr('line/style', currentStyle)
      }

      // 更新标签样式（如果有标签）
      const labels = edge.getLabels()
      if (labels && labels.length > 0) {
        const labelCfg = cfg.label
        const paddingPercent = 100 + (labelCfg.padding * 5)
        const offsetPercent = -(labelCfg.padding * 2.5)

        edge.setLabels([
          {
            attrs: {
              body: {
                fill: labelCfg.backgroundColor,
                stroke: labelCfg.borderColor,
                strokeWidth: labelCfg.borderWidth,
                rx: labelCfg.borderRadius,
                ry: labelCfg.borderRadius,
                refWidth: (labelCfg.paddingX ?? labelCfg.padding) * 2,
                refHeight: (labelCfg.paddingY ?? labelCfg.padding) * 2,
                refX: -(labelCfg.paddingX ?? labelCfg.padding),
                refY: -(labelCfg.paddingY ?? labelCfg.padding) + (labelCfg.offsetY ?? 0),
                filter: {
                  name: 'dropShadow',
                  args: { dx: 0, dy: 1, stdDeviation: 2, color: 'rgba(0,0,0,0.10)' },
                },
              },
              text: {
                fill: labelCfg.textColor,
                fontSize: labelCfg.fontSize,
                fontWeight: labelCfg.fontWeight,
                textAnchor: labelCfg.textAnchor,
                textVerticalAnchor: labelCfg.textVerticalAnchor,
                pointerEvents: labelCfg.pointerEvents,
                text: labels[0].attrs?.text?.text || '',
              },
            },
            position: { distance: labelCfg.position },
          },
        ])
      }
    })
  }

  // ─── 应用交互配置 ──────────────────────────────────────────────────────────────

  private applyInteractionConfig(graph: Graph, transform?: Transform | null, capabilities?: ModeCapabilities): void {
    const cfg = this.config.interaction

    // 平移（Scroller / Panning）
    if (cfg.panning) {
      graph.enablePanning()
    } else {
      graph.disablePanning()
    }

    // 鼠标滚轮缩放
    if (cfg.mousewheel) {
      graph.enableMouseWheel()
    } else {
      graph.disableMouseWheel()
    }

    // 框选（Rubberband）：配置启用 且 权限允许（canMultipleSelect），才真正开启
    // 权限优先级高于配置：权限禁用时即使配置开启也不生效
    const rubberbandAllowed = capabilities ? capabilities.canMultipleSelect : true
    if (cfg.rubberband && rubberbandAllowed) {
      graph.enableRubberband()
    } else {
      graph.disableRubberband()
    }

    // 多选（multiple）：同上，写入 Selection 插件 options
    const multipleAllowed = capabilities ? capabilities.canMultipleSelect : true
    const selectionPlugin = (graph as any).selection
    if (selectionPlugin?.options) {
      selectionPlugin.options.multiple = cfg.multipleSelection && multipleAllowed
    }

    // 节点可移动控制权完全交给权限系统（canDrag），画布配置不再干预
    // 理由：权限是业务语义（如 readonly 模式不可拖拽），优先级应高于 UI 配置
    // interaction.movable 配置项保留但不应用到 Graph，避免与权限冲突

    // 节点可调整大小（通过 Transform 插件实例直接修改）
    // 🔑 权限优先：canTransform && resizable（双重控制）
    if (transform) {
      const resizingOptions = (transform as any).options?.resizing
      if (resizingOptions !== undefined) {
        // 权限控制：只有在权限允许且画布配置启用时才真正启用
        const canTransform = capabilities?.canTransform ?? false
        const canvasResizable = cfg.resizable
        resizingOptions.enabled = canTransform && canvasResizable
      }
    }
  }

  // ─── 工具方法 ───────────────────────────────────────────────────────────────

  private mergeConfig(
    base: CanvasConfig,
    override?: Partial<CanvasConfig>
  ): CanvasConfig {
    if (!override) return JSON.parse(JSON.stringify(base))

    const merged = JSON.parse(JSON.stringify(base))

    // 深度合并每个配置项
    if (override.grid) Object.assign(merged.grid, override.grid)
    if (override.align) Object.assign(merged.align, override.align)
    
    // ✅ 修复: connection 需要深度合并 label 子对象，避免浅合并覆盖默认配置
    if (override.connection) {
      // 先排除 label，避免浅合并覆盖
      const { label, ...connectionWithoutLabel } = override.connection
      Object.assign(merged.connection, connectionWithoutLabel)
      if (label) {
        Object.assign(merged.connection.label, label)
      }
    }
    
    if (override.interaction) Object.assign(merged.interaction, override.interaction)
    
    // ✅ 修复: highlight 需要深度合并嵌套对象，避免覆盖默认配置
    if (override.highlight) {
      // 逐个子对象合并，保留默认值
      if (override.highlight.nodeHover) 
        Object.assign(merged.highlight.nodeHover, override.highlight.nodeHover)
      if (override.highlight.nodeSelected) 
        Object.assign(merged.highlight.nodeSelected, override.highlight.nodeSelected)
      if (override.highlight.edgeHover) 
        Object.assign(merged.highlight.edgeHover, override.highlight.edgeHover)
      if (override.highlight.edgeHoverOverlap) 
        Object.assign(merged.highlight.edgeHoverOverlap, override.highlight.edgeHoverOverlap)
      if (override.highlight.edgeSelected) 
        Object.assign(merged.highlight.edgeSelected, override.highlight.edgeSelected)
      if (override.highlight.portDefault) 
        Object.assign(merged.highlight.portDefault, override.highlight.portDefault)
      if (override.highlight.portHover) 
        Object.assign(merged.highlight.portHover, override.highlight.portHover)
      if (override.highlight.magnetAdsorbed) 
        Object.assign(merged.highlight.magnetAdsorbed, override.highlight.magnetAdsorbed)
      if (override.highlight.magnetAvailable) 
        Object.assign(merged.highlight.magnetAvailable, override.highlight.magnetAvailable)
      if (override.highlight.nodeHoverOutEdgeFlow) 
        Object.assign(merged.highlight.nodeHoverOutEdgeFlow, override.highlight.nodeHoverOutEdgeFlow)
    }
    
    if (override.background) Object.assign(merged.background, override.background)
    if (override.minimap) Object.assign(merged.minimap, override.minimap)
    if (override.history) Object.assign(merged.history, override.history)
    if (override.tooltip) Object.assign(merged.tooltip, override.tooltip)

    return merged
  }
}
