/**
 * nodeSlotRegistry.ts
 *
 * 模块级全局单例注册表。
 *
 * 为什么不用 provide/inject：
 *   @antv/x6-vue-shape 在 X6 内部创建了独立的 Vue app 实例来挂载节点组件，
 *   该 app 实例不在 FlowDesignerLayout 的组件树中，inject 无法跨 app 实例传递。
 *
 * 解决方案：
 *   使用 ES 模块天然单例的特性，将注册表和宿主 appContext 存储在模块作用域中，
 *   FlowDesignerLayout 写入，CommonVueNode 直接 import 读取。
 *
 * 响应式更新：
 *   每次 FlowDesignerLayout 更新插槽时，递增 registryVersion。
 *   CommonVueNode 用 watchEffect 监听 registryVersion，触发重新渲染。
 */

import type { Node, Graph } from '@antv/x6'
import type { AppContext, VNode, Ref } from 'vue'
import { shallowRef } from 'vue'

// ─── 类型定义 ─────────────────────────────────────────────────────────────────

/** slot 渲染函数的 scope 参数 */
export interface NodeSlotScope {
  /** X6 Node 实例（原始 API，不响应变化） */
  node: Node
  /** X6 Graph 实例，用于监听 cell:selected 等全局事件 */
  graph: Graph | null
  /** 当前 node-type 字符串 */
  nodeType: string
  /** 响应式 data（✅ 推荐使用，自动响应 setData 变化） */
  data: Ref<Record<string, any>>
  /** 响应式 label（✅ 推荐使用，自动响应 setProp('label') 变化） */
  label: Ref<string>
  /** 响应式 state（✅ 推荐使用，自动响应 setProp('_state') 变化） */
  state: Ref<string>
}

/** slot 渲染函数签名：接收 scope，返回 VNode 数组 */
export type SlotRenderFn = (scope: NodeSlotScope) => VNode[]

// ─── 模块级单例 ───────────────────────────────────────────────────────────────

/**
 * 全局 slot 渲染函数注册表
 * key: node-type 字符串（如 'custom-task'）
 * value: slot 渲染函数
 */
export const globalNodeSlotRegistry = new Map<string, SlotRenderFn>()

/**
 * 版本号（shallowRef）：每次注册表内容变化时 +1
 * CommonVueNode 通过 watchEffect 监听此值，触发响应式重渲染
 */
export const registryVersion = shallowRef(0)

/**
 * 宿主 Vue app 的 appContext
 * 在 FlowDesignerLayout 挂载时写入，供 CommonVueNode 创建 VNode 时使用，
 * 确保 slot 内容能访问宿主 app 的全局组件、directive、provide 等
 */
export let hostAppContext: AppContext | null = null

/** 由 FlowDesignerLayout 调用，注册宿主 appContext */
export function setHostAppContext(ctx: AppContext) {
  hostAppContext = ctx
}

/**
 * 更新全局注册表（由 FlowDesignerLayout 调用）
 * 传入当前所有 node-* 插槽的渲染函数 Map，全量替换并递增版本号
 */
export function updateNodeSlotRegistry(entries: Map<string, SlotRenderFn>) {
  globalNodeSlotRegistry.clear()
  entries.forEach((fn, key) => globalNodeSlotRegistry.set(key, fn))
  // 递增版本号，触发所有 CommonVueNode 的 watchEffect 重新执行
  registryVersion.value++
}
