<template>
  <div class="mode-selection">
    <!-- 模式切换器 -->
    <a-segmented
      :value="currentMode"
      size="small"
      :options="modeOptions"
      @change="handleModeChange"
    />

    <!-- 设置按钮 -->
    <a-tooltip title="权限配置">
      <SettingOutlined
        class="mode-selection__settings"
        @click="showModal = true"
      />
    </a-tooltip>
  </div>

  <!-- 权限配置弹框 -->
  <a-modal
    v-model:open="showModal"
    title="权限配置"
    width="1200px"
    :body-style="{ maxHeight: '70vh', overflowY: 'auto', padding: '16px' }"
    @cancel="handleCancel"
    wrap-class-name="mode-selection-modal"
  >
    <template #footer>
      <a-button @click="handleCancel">取消</a-button>
      <a-button type="primary" @click="handleSave">保存并应用</a-button>
    </template>

    <div class="permission-config">
      <!-- 遍历固定的权限分组 -->
      <div
        v-for="group in permissionGroups"
        :key="group.key"
        class="permission-group"
      >
        <!-- 分组标题 -->
        <div class="permission-group__header">
          <component :is="group.icon" class="permission-group__icon" />
          <span class="permission-group__title">{{ group.label }}</span>
        </div>

        <!-- 权限表格 -->
        <table class="permission-table">
          <thead>
            <tr>
              <th class="permission-table__name">权限名称</th>
              <th class="permission-table__desc">权限描述</th>
              <!-- 动态渲染所有模式的列头 -->
              <th
                v-for="(mode, index) in availableModes"
                :key="mode"
                class="permission-table__mode"
                :class="`permission-table__mode--${index + 2}`"
              >
                {{ getModeLabel(mode) }}
                <span v-if="mode != 'design' && mode != 'readonly' && mode != 'preview'"> - 自定义模式</span>
              </th>
            </tr>
          </thead>
          <tbody>
            <tr v-for="permission in group.permissions" :key="permission.key">
              <td class="permission-table__name">
                <a-tooltip v-if="permission.description" :title="permission.description">
                  <span>{{permission.key}}</span>
                  <InfoCircleOutlined class="permission-table__info" />
                </a-tooltip>
                <span v-else>{{ permission.label }}</span>
              </td>
              <td class="permission-table__desc">
                <a-tooltip v-if="permission.description" :title="permission.description">
                  <span>{{permission.label}}</span>
                  <InfoCircleOutlined class="permission-table__info" />
                </a-tooltip>
              </td>
              <!-- 动态渲染所有模式的 checkbox -->
              <td
                v-for="(mode, index) in availableModes"
                :key="mode"
                class="permission-table__checkbox"
                :class="`permission-table__checkbox--${index + 2}`"
              >
                <a-checkbox
                  v-if="editingConfig[mode]"
                  v-model:checked="editingConfig[mode][permission.key]"
                />
                <span v-else class="permission-table__loading">-</span>
              </td>
            </tr>
          </tbody>
        </table>
      </div>

      <!-- 动态检测的"其他权限"分组（用户自定义扩展） -->
      <div
        v-if="unknownPermissions.length > 0"
        class="permission-group permission-group--unknown"
      >
        <!-- 分组标题 -->
        <div class="permission-group__header">
          <QuestionCircleOutlined class="permission-group__icon" />
          <span class="permission-group__title">其他权限（自定义扩展）</span>
          <a-tag color="orange" style="margin-left: 8px">{{ unknownPermissions.length }}</a-tag>
        </div>

        <!-- 权限表格 -->
        <table class="permission-table">
          <thead>
            <tr>
              <th class="permission-table__name">权限参数名</th>
              <!-- 动态渲染所有模式的列头 -->
              <th
                v-for="(mode, index) in availableModes"
                :key="mode"
                class="permission-table__mode"
                :class="`permission-table__mode--${index + 2}`"
              >
                {{ getModeLabel(mode) }}
              </th>
            </tr>
          </thead>
          <tbody>
            <!-- 遍历未知权限，只显示参数名和 checkbox -->
            <tr v-for="permissionKey in unknownPermissions" :key="permissionKey">
              <td class="permission-table__name permission-table__name--code">
                <code>{{ permissionKey }}</code>
              </td>
              <!-- 动态渲染所有模式的 checkbox -->
              <td
                v-for="(mode, index) in availableModes"
                :key="mode"
                class="permission-table__checkbox"
                :class="`permission-table__checkbox--${index + 2}`"
              >
                <a-checkbox
                  v-if="editingConfig[mode]"
                  v-model:checked="editingConfig[mode][permissionKey]"
                />
                <span v-else class="permission-table__loading">-</span>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </a-modal>
</template>

<script setup lang="ts">
import { ref, reactive, watch, computed } from 'vue'
import {
  SettingOutlined,
  InfoCircleOutlined,
  QuestionCircleOutlined,
  LayoutOutlined,
  EditOutlined,
  SelectOutlined,
  HistoryOutlined,
  EyeOutlined,
  ImportOutlined,
} from '@ant-design/icons-vue'
import type { DesignerMode } from './types/flow.types'
import type { FlowDesigner } from '../components/FlowDesigner/core'

// ─── Props ───────────────────────────────────────────────────────────────────
const props = defineProps<{
  designer: FlowDesigner | null
}>()

// ─── Emits ───────────────────────────────────────────────────────────────────
const emit = defineEmits<{
  (e: 'modeChange', mode: DesignerMode): void
}>()

// ─── 当前模式 ────────────────────────────────────────────────────────────────
const currentMode = computed(() => {
  return props.designer?.getMode() || 'design'
})

// ─── 模式选项（动态） ────────────────────────────────────────────────────────
const modeOptions = computed(() => {
  const modes = props.designer?.getAvailableModes() || ['design', 'readonly', 'preview']
  return modes.map(mode => {
    const labels: Record<string, string> = {
      design: '✏️ 设计',
      readonly: '👁️ 只读',
      preview: '📺 预览',
    }
    return {
      label: labels[mode] || `📋 ${mode}`,
      value: mode
    }
  })
})

// ─── 权限分组配置（仅前端展示用） ────────────────────────────────────────────
interface PermissionItem {
  key: string
  label: string
  description?: string
}

interface PermissionGroup {
  key: string
  label: string
  icon: any
  permissions: PermissionItem[]
}

const permissionGroups: PermissionGroup[] = [
  {
    key: 'layout',
    label: '界面布局',
    icon: LayoutOutlined,
    permissions: [
      { key: 'showToolbar', label: '显示工具栏', description: '控制顶部工具栏的显示/隐藏' },
      { key: 'showNodePalette', label: '显示节点面板', description: '控制左侧节点面板的显示/隐藏' },
      { key: 'showPropertiesPanel', label: '显示属性面板', description: '控制右侧属性面板的显示/隐藏' },
      { key: 'showContextMenu', label: '显示右键菜单', description: '控制右键菜单的显示/隐藏' },
      { key: 'showMinimap', label: '显示小地图', description: '控制右下角小地图的显示/隐藏' },
      { key: 'showSearch', label: '显示搜索框', description: '控制搜索框的显示/隐藏（Ctrl+F）' },
    ]
  },
  {
    key: 'edit',
    label: '编辑操作',
    icon: EditOutlined,
    permissions: [
      { key: 'canAddNode', label: '添加节点', description: '允许从节点面板拖拽添加新节点' },
      { key: 'canDrag', label: '拖动节点', description: '允许拖动节点改变位置' },
      { key: 'canConnect', label: '创建连线', description: '允许创建节点之间的连线' },
      { key: 'canDelete', label: '删除节点/连线', description: '允许删除节点和连线' },
      { key: 'canCopy', label: '复制节点', description: '允许复制节点 (Ctrl+C)' },
      { key: 'canPaste', label: '粘贴节点', description: '允许粘贴节点 (Ctrl+V)' },
      { key: 'canTransform', label: '节点变形', description: '允许节点变形' },
      { key: 'canGroup', label: '节点成组', description: '允许将多个节点组合成组' },
      { key: 'canToFront', label: '层级前置', description: '允许将节点移到最前层' },
      { key: 'canToBack', label: '层级后置', description: '允许将节点移到最后层' },
      { key: 'canAlign', label: '对齐节点', description: '允许对齐节点（总开关）' },
      { key: 'canAlignLeft', label: '左对齐', description: '允许节点左对齐' },
      { key: 'canAlignRight', label: '右对齐', description: '允许节点右对齐' },
      { key: 'canAlignTop', label: '上对齐', description: '允许节点上对齐' },
      { key: 'canAlignBottom', label: '下对齐', description: '允许节点下对齐' },
    ]
  },
  {
    key: 'select',
    label: '选择操作',
    icon: SelectOutlined,
    permissions: [
      { key: 'canSelectNode', label: '选中节点', description: '允许选中节点' },
      { key: 'canSelectEdge', label: '选中连线', description: '允许选中连线' },
      { key: 'canMultipleSelect', label: '多选节点', description: '允许同时选中多个节点' },
      { key: 'canSelectAll', label: '全选节点', description: '允许全选所有节点 (Ctrl+A)' },
      { key: 'canSelectCanvas', label: '选中画布', description: '允许选中画布(选中画布时会还原所有元素状态为default)' },
    ]
  },
  {
    key: 'history',
    label: '历史操作',
    icon: HistoryOutlined,
    permissions: [
      { key: 'canUndo', label: '撤销操作', description: '允许撤销上一步操作 (Ctrl+Z)' },
      { key: 'canRedo', label: '重做操作', description: '允许重做上一步操作 (Ctrl+Y)' },
    ]
  },
  {
    key: 'view',
    label: '视图操作',
    icon: EyeOutlined,
    permissions: [
      { key: 'canZoom', label: '缩放画布', description: '允许缩放画布 (Ctrl +/-)' },
      { key: 'canPan', label: '拖拽画布', description: '允许拖拽画布平移视图' },
      { key: 'canFitView', label: '适应窗口', description: '允许自动适应窗口大小 (Ctrl+0)' },
      { key: 'canResetView', label: '重置视图', description: '允许重置视图到初始状态' },
      { key: 'canHoverNode', label: 'Hover 节点高亮', description: '鼠标悬停时高亮节点' },
      { key: 'canHoverEdge', label: 'Hover 连线高亮', description: '鼠标悬停时高亮连线' },
    ]
  },
  {
    key: 'io',
    label: '导入导出',
    icon: ImportOutlined,
    permissions: [
      { key: 'canImport', label: '导入 JSON', description: '允许导入流程数据' },
      { key: 'canExport', label: '导出 JSON', description: '允许导出流程数据' },
    ]
  },
  {
    key: 'tooltip',
    label: '提示信息',
    icon: InfoCircleOutlined,
    permissions: [
      { key: 'canNodeTooltip', label: '节点提示', description: '显示节点的 Tooltip 提示' },
      { key: 'canEdgeTooltip', label: '连线提示', description: '显示连线的 Tooltip 提示' },
    ]
  }
]

// ─── 收集所有已知的权限 key ──────────────────────────────────────────────────
const knownPermissionKeys = new Set(
  permissionGroups.flatMap(group => group.permissions.map(p => p.key))
)

// ─── 动态检测未知权限（用户自定义的权限）─────────────────────────────────────
const unknownPermissions = computed(() => {
  const unknown: string[] = []

  // 遍历所有模式的权限配置
  Object.values(editingConfig).forEach(modeConfig => {
    if (modeConfig && typeof modeConfig === 'object') {
      Object.keys(modeConfig).forEach(key => {
        // 如果不在已知权限列表中，且未添加过
        if (!knownPermissionKeys.has(key) && !unknown.includes(key)) {
          unknown.push(key)
        }
      })
    }
  })

  // 按字母顺序排序，保持一致性
  const sorted = unknown.sort()

  console.log('[ModeSelection] 检测到未知权限：', sorted)
  console.log('[ModeSelection] 已知权限数量：', knownPermissionKeys.size)
  console.log('[ModeSelection] 未知权限数量：', sorted.length)

  return sorted
})

// ─── 状态管理 ────────────────────────────────────────────────────────────────
const showModal = ref(false)

// 编辑态的临时配置（初始化基础模式）
const editingConfig = reactive<Record<string, Record<string, boolean>>>({
  design: {},
  readonly: {},
  preview: {},
})

// 获取所有可用的模式（动态，包括扩展模式）
const availableModes = computed(() => {
  return props.designer?.getAvailableModes() || ['design', 'readonly', 'preview']
})

// ─── 监听弹框打开，从 designer 获取完整权限配置 ──────────────────────────────
watch(showModal, (visible) => {
  console.log('visiblevisiblevvvssssss11111::', visible,props.designer);
  if (visible && props.designer) {

    try {
      // 🎯 从 designer 获取所有模式的完整权限配置（已补全默认值）
      const allPermissions = props.designer.getAllPermissions()

      console.log('[ModeSelection] 获取到权限配置：', allPermissions)
      console.log('[ModeSelection] 权限配置分组的 keys：', Object.keys(allPermissions))

      // 🛡️ 先清空 editingConfig
      Object.keys(editingConfig).forEach(key => {
        delete editingConfig[key]
      })

      // 🛡️ 防御性深拷贝到编辑态
      Object.keys(allPermissions).forEach(mode => {
        const modePermissions = allPermissions[mode]

        console.log(`[ModeSelection] 处理模式 ${mode}:`, modePermissions)

        // 确保 modePermissions 是有效对象
        if (modePermissions && typeof modePermissions === 'object') {
          editingConfig[mode] = { ...modePermissions }
          console.log(`[ModeSelection] 初始化模式 ${mode} 成功:`, editingConfig[mode])
        } else {
          console.warn(`[ModeSelection] 模式 ${mode} 的权限配置无效，使用空对象`, modePermissions)
          editingConfig[mode] = {}
        }
      })

      // 🛡️ 确保基础模式存在（即使 designer 没有返回）
      const basicModes = ['design', 'readonly', 'preview']
      basicModes.forEach(mode => {
        if (!editingConfig[mode]) {
          console.warn(`[ModeSelection] 基础模式 ${mode} 未初始化，使用空对象`)
          editingConfig[mode] = {}
        }
      })

      console.log('[ModeSelection] 最终编辑配置：', editingConfig)
      console.log('[ModeSelection] editingConfig.design 存在?', !!editingConfig.design)
      console.log('[ModeSelection] editingConfig.readonly 存在?', !!editingConfig.readonly)
      console.log('[ModeSelection] editingConfig.preview 存在?', !!editingConfig.preview)
    } catch (error) {
      console.error('[ModeSelection] 获取权限配置失败：', error)
      // 初始化为空对象，防止渲染错误
      Object.keys(editingConfig).forEach(key => {
        delete editingConfig[key]
      })
      editingConfig.design = {}
      editingConfig.readonly = {}
      editingConfig.preview = {}
    }
  }
})

// ─── 事件处理 ────────────────────────────────────────────────────────────────
function handleModeChange(mode: string) {
  console.log('handleModeChangehandleModeChange::', handleModeChange);
  emit('modeChange', mode as DesignerMode)
}

function handleSave() {
  if (!props.designer) return

  // 🎯 调用 designer.updatePermissions() 更新权限
  props.designer.updatePermissions(editingConfig)
  showModal.value = false

  console.log('[ModeSelection] 权限配置已保存：', editingConfig)
}

function handleCancel() {
  showModal.value = false
}

// 获取模式的显示标签
function getModeLabel(mode: string): string {
  const labels: Record<string, string> = {
    design: '✏️ 设计',
    readonly: '👁️ 只读',
    preview: '📺 预览',
  }
  return labels[mode] || `📋 ${mode}`
}
</script>

<style scoped>
:global(.mode-selection-modal) {
  z-index: 9999 !important;
}
/* ─── 模式选择器（固定在右上角）─────────────────────────────────────────── */
.mode-selection {
  position: absolute;
  top: 16px;
  right: 16px;
  z-index: 1000;
  display: flex;
  align-items: center;
  gap: 12px;
  background: #fff;
  padding: 8px 16px;
  border-radius: 8px;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.08);
}

.mode-selection__settings {
  font-size: 18px;
  cursor: pointer;
  color: #666;
  transition: all 0.2s;
  padding: 4px;
  border-radius: 4px;
}

.mode-selection__settings:hover {
  color: #1890ff;
  background: #f0f7ff;
}

/* ─── 权限配置弹框内容 ─────────────────────────────────────────────────── */
.permission-config {
  padding: 0;
}

.permission-group {
  margin-bottom: 24px;
}

.permission-group:last-child {
  margin-bottom: 0;
}

.permission-group__header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 12px;
  padding-bottom: 8px;
  border-bottom: 2px solid #1890ff;
}

.permission-group__icon {
  font-size: 16px;
  color: #1890ff;
}

.permission-group__title {
  font-size: 14px;
  font-weight: 600;
  color: #262626;
}

/* ─── "其他权限"分组特殊样式 ──────────────────────────────────────────── */
.permission-group--unknown .permission-group__header {
  border-bottom-color: #faad14;
}

.permission-group--unknown .permission-group__icon {
  color: #faad14;
}

.permission-group--unknown .permission-group__title {
  color: #d46b08;
}

/* ─── 权限参数名样式（code 风格）────────────────────────────────────── */
.permission-table__name--code {
  font-family: 'Consolas', 'Monaco', 'Courier New', monospace;
}

.permission-table__name--code code {
  background: #f5f5f5;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 12px;
  color: #d46b08;
  border: 1px solid #ffe7ba;
}

/* ─── 权限表格样式 ─────────────────────────────────────────────────────── */
.permission-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}

.permission-table thead {
  background: #fafafa;
}

.permission-table thead th {
  padding: 10px 12px;
  text-align: left;
  font-weight: 600;
  color: #595959;
  border: 1px solid #f0f0f0;
}

.permission-table thead th.permission-table__name {
  width: 18%;
}
.permission-table__desc {
  width: 18%;
}

.permission-table thead th.permission-table__mode {
  width: 16%;
  text-align: center;
}

/* ─── 设计模式列 - 橙色主题 ──────────────────────────────────────────── */
.permission-table thead th:nth-child(3) {
  background: linear-gradient(135deg, #fff5f0 0%, #ffe7d9 100%);
  color: #d46b08;
  font-weight: 700;
  border-left: 3px solid #ff9500;
}

/* ─── 只读模式列 - 蓝色主题 ──────────────────────────────────────────── */
.permission-table thead th:nth-child(4) {
  background: linear-gradient(135deg, #f0f7ff 0%, #d9ebff 100%);
  color: #0958d9;
  font-weight: 700;
  border-left: 3px solid #1890ff;
}

/* ─── 预览模式列 - 紫色主题 ──────────────────────────────────────────── */
.permission-table thead th:nth-child(5) {
  background: linear-gradient(135deg, #f9f0ff 0%, #efdbff 100%);
  color: #531dab;
  font-weight: 700;
  border-left: 3px solid #722ed1;
}

.permission-table tbody tr {
  transition: background 0.2s;
}

.permission-table tbody tr:hover {
  background: transparent;
}

.permission-table tbody td {
  padding: 10px 12px;
  border: 1px solid #f0f0f0;
}

/* ─── 设计模式列 - 淡橙色背景 ──────────────────────────────────────── */
.permission-table tbody td:nth-child(2) {
  background: rgba(255, 149, 0, 0.03);
  border-left: 2px solid rgba(255, 149, 0, 0.15);
}

/* ─── 只读模式列 - 淡蓝色背景 ──────────────────────────────────────── */
.permission-table tbody td:nth-child(3) {
  background: rgba(24, 144, 255, 0.03);
  border-left: 2px solid rgba(24, 144, 255, 0.15);
}

/* ─── 预览模式列 - 淡紫色背景 ──────────────────────────────────────── */
.permission-table tbody td:nth-child(4) {
  background: rgba(114, 46, 209, 0.03);
  border-left: 2px solid rgba(114, 46, 209, 0.15);
}

/* ─── Hover 时增强列的颜色 ───────────────────────────────────────── */
.permission-table tbody tr:hover td:nth-child(2) {
  background: rgba(255, 149, 0, 0.08);
}

.permission-table tbody tr:hover td:nth-child(3) {
  background: rgba(24, 144, 255, 0.08);
}

.permission-table tbody tr:hover td:nth-child(4) {
  background: rgba(114, 46, 209, 0.08);
}

.permission-table tbody td.permission-table__name {
  color: #262626;
  background: #fff;
}

.permission-table tbody tr:hover td.permission-table__name {
  background: #fafafa;
}

.permission-table tbody td.permission-table__name .permission-table__info {
  margin-left: 6px;
  color: #8c8c8c;
  font-size: 12px;
  cursor: help;
}

.permission-table tbody td.permission-table__checkbox {
  text-align: center;
}

.permission-table tbody td .permission-table__loading {
  color: #bfbfbf;
  font-size: 12px;
}
</style>
