<template>
  <a-form :model="form" layout="vertical" size="small">
    <a-tabs>
      <!-- 基本信息 -->
      <a-tab-pane key="basic" tab="基本">
        <a-form-item label="节点名称">
          <a-input v-model:value="form.label" @change="emit('update', { ...form })" />
        </a-form-item>
        <a-form-item label="节点说明">
          <a-textarea
            v-model:value="form.description"
            :rows="2"
            @change="emit('update', { ...form })"
          />
        </a-form-item>
      </a-tab-pane>

      <!-- 审批配置 -->
      <a-tab-pane key="approver" tab="审批">
        <a-form-item label="审批类型">
          <a-radio-group v-model:value="form.approverType" @change="emit('update', { ...form })">
            <a-space direction="vertical">
                                                        <a-radio value="user">指定人员</a-radio>
              <a-radio value="role">指定角色</a-radio>
              <a-radio value="superior">发起人上级</a-radio>
              <a-radio value="deptHead">部门负责人</a-radio>
            </a-space>
          </a-radio-group>
        </a-form-item>

        <a-form-item v-if="form.approverType === 'user'" label="审批人">
          <a-select
            v-model:value="form.approvers"
            mode="multiple"
            :placeholder="'请选择审批人'"
            @change="emit('update', { ...form })"
          >
            <a-select-option v-for="u in mockUsers" :key="u.id" :value="u.id">
              {{ u.name }} · {{ u.dept }}
            </a-select-option>
          </a-select>
        </a-form-item>

        <a-form-item v-if="form.approverType === 'role'" label="审批角色">
          <a-select
            v-model:value="form.roles"
            mode="multiple"
            :placeholder="'请选择角色'"
            @change="emit('update', { ...form })"
          >
            <a-select-option v-for="r in mockRoles" :key="r.id" :value="r.id">
              {{ r.name }}
            </a-select-option>
          </a-select>
        </a-form-item>

        <!-- 会签/或签 额外字段 -->
        <template v-if="isMultiSign">
          <a-form-item label="通过条件">
            <a-radio-group v-model:value="passMode" @change="handlePassModeChange">
                                                        <a-radio value="all">全部通过</a-radio>
              <a-radio value="percent">百分比通过</a-radio>
            </a-radio-group>
          </a-form-item>
          <a-form-item v-if="passMode === 'percent'" label="通过百分比">
            <a-row :gutter="8" align="middle">
              <a-col :span="16">
                <a-slider v-model:value="form.passPercent" :min="1" :max="100" @change="emit('update', { ...form })" />
              </a-col>
              <a-col :span="8">
                <a-input-number
                  v-model:value="form.passPercent"
                  :min="1" :max="100"
                  style="width: 100%"
                  @change="emit('update', { ...form })"
                />
              </a-col>
            </a-row>
          </a-form-item>
        </template>

        <a-form-item label="审批意见">
          <a-radio-group v-model:value="form.commentRequired" @change="emit('update', { ...form })">
                                                <a-radio value="required">必填</a-radio>
            <a-radio value="optional">选填</a-radio>
            <a-radio value="none">不需要</a-radio>
          </a-radio-group>
        </a-form-item>
        <a-form-item label="允许转交">
          <a-switch v-model:checked="form.allowTransfer" @change="emit('update', { ...form })" />
        </a-form-item>
        <a-form-item label="允许加签">
          <a-switch v-model:checked="form.allowAddSign" @change="emit('update', { ...form })" />
        </a-form-item>
      </a-tab-pane>

      <!-- 超时配置 -->
      <a-tab-pane key="timeout" tab="超时">
        <a-form-item label="启用超时">
          <a-switch v-model:checked="form.timeoutEnabled" @change="emit('update', { ...form })" />
        </a-form-item>
        <template v-if="form.timeoutEnabled">
          <a-form-item label="超时时长（小时）">
            <a-input-number
              v-model:value="form.timeoutHours"
              :min="1" :max="720"
              style="width: 100%"
              @change="emit('update', { ...form })"
            />
          </a-form-item>
          <a-form-item label="超时动作">
            <a-select v-model:value="form.timeoutAction" @change="emit('update', { ...form })">
                                                        <a-select-option value="pass">自动通过</a-select-option>
              <a-select-option value="reject">自动拒绝</a-select-option>
              <a-select-option value="notify">通知催办</a-select-option>
            </a-select>
          </a-form-item>
        </template>
      </a-tab-pane>
    </a-tabs>
  </a-form>
</template>

<script setup lang="ts">
import { reactive, ref, watch } from 'vue'
import type { Node } from '@antv/x6'
import type { FlowNodeData, MockUser, MockRole } from '../types/flow.types'

const props = defineProps<{ node: Node }>()
const emit  = defineEmits<{ (e: 'update', data: FlowNodeData): void }>()
const isMultiSign = ['countersign-node', 'orsign-node'].includes(props.node.shape)
const passMode    = ref<'all' | 'percent'>('all')
const form = reactive<FlowNodeData>({ label: '', ...props.node.getData() })

watch(
  () => props.node.getData(),
  (d) => { if (d) Object.assign(form, d) },
  { deep: true }
)

function handlePassModeChange() {
  form.passPercent = passMode.value === 'all' ? 100 : 60
  emit('update', { ...form })
}

const mockUsers: MockUser[] = [
  { id: 'u1', name: '张三', dept: '研发部' },
  { id: 'u2', name: '李四', dept: '产品部' },
  { id: 'u3', name: '王五', dept: '财务部' },
  { id: 'u4', name: '赵六', dept: 'HR部'  },
]
const mockRoles: MockRole[] = [
  { id: 'r1', name: '部门经理' },
  { id: 'r2', name: '项目负责人' },
  { id: 'r3', name: '财务审计' },
]
</script>
