<template>
  <div class="cvn-notice" data-cvn-root :class="{ 'cvn-notice--selected': isSelected }">
    <div class="cvn-notice__bar" />
    <div class="cvn-notice__body">
      <div class="cvn-notice__title">{{ nodeData.label || '通知节点' }}</div>
      <div class="cvn-notice__methods">通知方式：{{ methodsText }}--{{isSelected}}</div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted } from 'vue'
import type { Node, Graph } from '@antv/x6'

// graph 通过 slot scope 以 prop 形式传入，不再依赖 inject
const props = defineProps<{
  node: Node
  graph: Graph | null
}>()

const nodeData   = ref<Record<string, any>>(props.node.getData() ?? {})
const isSelected = ref(false)

const onDataChange = () => { nodeData.value = props.node.getData() ?? {} }

const methodsText = computed(() =>
  (nodeData.value.methods as string[] | undefined)?.join('、') || '站内信'
)

function onSelected({ cell }: { cell: { id: string } }) {
  if (cell.id === props.node.id) isSelected.value = true
}
function onUnselected({ cell }: { cell: { id: string } }) {
  if (cell.id === props.node.id) isSelected.value = false
}

onMounted(() => {
  props.node.on('change:data', onDataChange)
  if (props.graph) {
    props.graph.on('cell:selected',   onSelected)
    props.graph.on('cell:unselected', onUnselected)
  }
})

onUnmounted(() => {
  props.node.off('change:data', onDataChange)
  if (props.graph) {
    props.graph.off('cell:selected',   onSelected)
    props.graph.off('cell:unselected', onUnselected)
  }
})
</script>

<style scoped>
.cvn-notice {
  display: flex;
  flex-direction: column;
  min-width: 260px;
  height: 80px;
  background: #fff;
  border: 1.5px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  user-select: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.cvn-notice:hover {
  border-color: #95de64;
}

.cvn-notice--selected {
  border: 2px solid #52c41a;
  box-shadow: 0 0 0 3px rgba(82, 196, 26, 0.15);
}

.cvn-notice__bar {
  height: 4px;
  flex-shrink: 0;
  background: linear-gradient(90deg, #52c41a 0%, #95de64 100%);
}

.cvn-notice__body {
  padding: 10px 14px;
}

.cvn-notice__title {
  font-size: 13px;
  font-weight: 600;
  color: #262626;
}

.cvn-notice__methods {
  font-size: 11px;
  color: #8c8c8c;
  margin-top: 4px;
}
</style>
