<template>
  <!-- 菜单容器：始终由内部管理 Teleport + 定位 + 遮罩关闭 -->
  <Teleport to="body">
    <div
      v-if="state.visible"
      ref="menuContainerRef"
      class="fdl-ctx-menu-wrap"
      :style="{ left: state.x + 'px', top: state.y + 'px' }"
      @click.stop
    >
      <!-- 节点菜单 -->
      <template v-if="state.context?.type === 'node'">
        <!-- 有外部插槽：完全交给外部定义，暴露 capabilities 供权限判断 -->
        <slot
          v-if="hasNodeMenuSlot"
          name="node-menu"
          :node="state.context.target"
          :is-group="state.context.nodeCtx?.isGroup ?? false"
          :is-multi-select="state.context.nodeCtx?.isMultiSelect ?? false"
          :capabilities="capabilities"
          :designer="designer?.value ?? null"
          :graph="graph?.value ?? null"
          :on-select="handleSelect"
          :on-close="closeMenu"
        />
        <!-- 无插槽 fallback：内联渲染默认菜单项 -->
        <div v-else class="fdl-ctx-menu">
          <div
            v-for="(item, index) in state.items"
            :key="item.key || `divider-${index}`"
            class="fdl-ctx-menu__item"
            :class="{
              'fdl-ctx-menu__item--danger': item.danger,
              'fdl-ctx-menu__item--divider': item.divider,
              'fdl-ctx-menu__item--disabled': item.disabled,
            }"
            @click="!item.divider && !item.disabled && handleSelect(item.key)"
          >
            <template v-if="!item.divider">
              <component v-if="item.icon" :is="item.icon" class="fdl-ctx-menu__icon" />
              <span class="fdl-ctx-menu__label">{{ item.label }}</span>
            </template>
            <div v-else class="fdl-ctx-menu__divider" />
          </div>
        </div>
      </template>

      <!-- 连线菜单 -->
      <template v-else-if="state.context?.type === 'edge'">
        <slot
          v-if="hasEdgeMenuSlot"
          name="edge-menu"
          :edge="state.context.target"
          :capabilities="capabilities"
          :designer="designer?.value ?? null"
          :graph="graph?.value ?? null"
          :on-select="handleSelect"
          :on-close="closeMenu"
        />
        <div v-else class="fdl-ctx-menu">
          <div
            v-for="(item, index) in state.items"
            :key="item.key || `divider-${index}`"
            class="fdl-ctx-menu__item"
            :class="{
              'fdl-ctx-menu__item--danger': item.danger,
              'fdl-ctx-menu__item--divider': item.divider,
              'fdl-ctx-menu__item--disabled': item.disabled,
            }"
            @click="!item.divider && !item.disabled && handleSelect(item.key)"
          >
            <template v-if="!item.divider">
              <component v-if="item.icon" :is="item.icon" class="fdl-ctx-menu__icon" />
              <span class="fdl-ctx-menu__label">{{ item.label }}</span>
            </template>
            <div v-else class="fdl-ctx-menu__divider" />
          </div>
        </div>
      </template>

      <!-- 画布菜单 -->
      <template v-else-if="state.context?.type === 'canvas'">
        <slot
          v-if="hasCanvasMenuSlot"
          name="canvas-menu"
          :capabilities="capabilities"
          :designer="designer?.value ?? null"
          :graph="graph?.value ?? null"
          :on-select="handleSelect"
          :on-close="closeMenu"
        />
        <div v-else class="fdl-ctx-menu">
          <div
            v-for="(item, index) in state.items"
            :key="item.key || `divider-${index}`"
            class="fdl-ctx-menu__item"
            :class="{
              'fdl-ctx-menu__item--danger': item.danger,
              'fdl-ctx-menu__item--divider': item.divider,
              'fdl-ctx-menu__item--disabled': item.disabled,
            }"
            @click="!item.divider && !item.disabled && handleSelect(item.key)"
          >
            <template v-if="!item.divider">
              <component v-if="item.icon" :is="item.icon" class="fdl-ctx-menu__icon" />
              <span class="fdl-ctx-menu__label">{{ item.label }}</span>
            </template>
            <div v-else class="fdl-ctx-menu__divider" />
          </div>
        </div>
      </template>
    </div>
  </Teleport>
</template>

<script setup lang="ts">
import { reactive, inject, computed, ref, onMounted, onUnmounted, useSlots, watch, type ComputedRef } from 'vue'
import type { Node, Edge, Graph } from '@antv/x6'
import type { MenuContext } from './types'
import type { ModeCapabilities } from '../../../views/types/flow.types'
import type { FlowDesigner } from '../core'
import { useNodeMenu } from './useNodeMenu'
import { useEdgeMenu } from './useEdgeMenu'
import { useCanvasMenu } from './useCanvasMenu'

interface MenuState {
  visible: boolean
  x: number
  y: number
  items: any[]
  context: MenuContext | null
}

interface Emits {
  (e: 'action', payload: { type: string; action: string; target?: any }): void
}

const emit = defineEmits<Emits>()
const slots = useSlots()

const state = reactive<MenuState>({
  visible: false,
  x: 0,
  y: 0,
  items: [],
  context: null
})

const menuContainerRef = ref<HTMLElement | null>(null)

// ── 插槽检测 ──────────────────────────────────────────────────────────────────
const hasNodeMenuSlot = computed(() => !!slots['node-menu'])
const hasEdgeMenuSlot = computed(() => !!slots['edge-menu'])
const hasCanvasMenuSlot = computed(() => !!slots['canvas-menu'])

// ── 注入权限和核心对象 ────────────────────────────────────────────────────────
const capabilities = inject<ComputedRef<ModeCapabilities>>('capabilities')!
const designer = inject<ComputedRef<FlowDesigner | null>>('designer')
const graph = inject<ComputedRef<Graph | null>>('graph')

// ── fallback 用的默认菜单项生成器（仅无插槽时执行） ───────────────────────────
const { getNodeMenuItems } = useNodeMenu()
const { getEdgeMenuItems } = useEdgeMenu()
const { getCanvasMenuItems } = useCanvasMenu()

/**
 * 显示节点右键菜单
 * - 有插槽：items 留空，由外部插槽完全接管渲染，capabilities 通过 scope 透出
 * - 无插槽：生成内置默认菜单项作为 fallback
 */
function showNodeMenu(e: MouseEvent, node: Node, isGroup: boolean, isMultiSelect: boolean) {
  if (!capabilities.value.showContextMenu) return

  if (hasNodeMenuSlot.value) {
    // 有插槽：不生成 items，由外部插槽完全接管
    state.items = []
  } else {
    // 无插槽 fallback：生成内置默认菜单项
    const items = getNodeMenuItems(node, isGroup, isMultiSelect, capabilities.value)
    if (items.length === 0) return
    state.items = items
  }

  state.x = e.clientX
  state.y = e.clientY
  state.context = { type: 'node', target: node, nodeCtx: { isGroup, isMultiSelect } }
  state.visible = true
}

/**
 * 显示连线右键菜单
 * - 有插槽：items 留空，由外部插槽完全接管渲染
 * - 无插槽：生成内置默认菜单项作为 fallback
 */
function showEdgeMenu(e: MouseEvent, edge: Edge) {
  if (!capabilities.value.showContextMenu) return

  if (hasEdgeMenuSlot.value) {
    state.items = []
  } else {
    const items = getEdgeMenuItems(edge, capabilities.value)
    if (items.length === 0) return
    state.items = items
  }

  state.x = e.clientX
  state.y = e.clientY
  state.context = { type: 'edge', target: edge }
  state.visible = true
}

/**
 * 显示画布右键菜单
 * - 有插槽：items 留空，由外部插槽完全接管渲染
 * - 无插槽：生成内置默认菜单项作为 fallback
 */
function showCanvasMenu(e: MouseEvent) {
  if (!capabilities.value.showContextMenu) return

  if (hasCanvasMenuSlot.value) {
    state.items = []
  } else {
    const items = getCanvasMenuItems(capabilities.value)
    if (items.length === 0) return
    state.items = items
  }

  state.x = e.clientX
  state.y = e.clientY
  state.context = { type: 'canvas' }
  state.visible = true
}

/**
 * 关闭菜单
 */
function closeMenu() {
  state.visible = false
}

/**
 * 处理菜单项选择
 */
function handleSelect(key: string) {
  if (!state.context) return

  emit('action', {
    type: state.context.type,
    action: key,
    target: state.context.target
  })

  closeMenu()
}

// ── 自动调整位置，防止超出屏幕 ────────────────────────────────────────────────
function adjustPosition() {
  if (!menuContainerRef.value) return

  const rect = menuContainerRef.value.getBoundingClientRect()
  const { innerWidth, innerHeight } = window

  let newX = state.x
  let newY = state.y

  if (rect.right > innerWidth) newX = innerWidth - rect.width - 10
  if (rect.bottom > innerHeight) newY = innerHeight - rect.height - 10
  if (newX < 0) newX = 10
  if (newY < 0) newY = 10

  if (newX !== state.x || newY !== state.y) {
    menuContainerRef.value.style.left = newX + 'px'
    menuContainerRef.value.style.top = newY + 'px'
  }
}

watch(() => state.visible, (visible) => {
  if (visible) {
    setTimeout(() => adjustPosition(), 0)
  }
})

// ── 全局点击关闭 ──────────────────────────────────────────────────────────────
function handleGlobalClick(e: MouseEvent) {
  if (!state.visible) return
  const target = e.target as HTMLElement
  if (menuContainerRef.value && !menuContainerRef.value.contains(target)) {
    closeMenu()
  }
}

onMounted(() => {
  document.addEventListener('click', handleGlobalClick)
})

onUnmounted(() => {
  document.removeEventListener('click', handleGlobalClick)
})

// 暴露方法给父组件
defineExpose({
  showNodeMenu,
  showEdgeMenu,
  showCanvasMenu
})
</script>

<style scoped>
/* ── 菜单定位容器 ─────────────────────────────────────────────────────────── */
.fdl-ctx-menu-wrap {
  position: fixed;
  z-index: 9999;
}

/* ── fallback 内联默认菜单 ──────────────────────────────────────────────────── */
.fdl-ctx-menu {
  background: #fff;
  border: 1px solid #e8e8e8;
  border-radius: 6px;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
  padding: 4px 0;
  min-width: 160px;
  max-width: 280px;
  user-select: none;
}

.fdl-ctx-menu__item {
  padding: 7px 16px;
  font-size: 13px;
  color: #262626;
  cursor: pointer;
  transition: background 0.15s;
  display: flex;
  align-items: center;
  gap: 8px;
}

.fdl-ctx-menu__item:hover {
  background: #f5f5f5;
}

.fdl-ctx-menu__item--danger {
  color: #f5222d;
}

.fdl-ctx-menu__item--disabled {
  color: #bfbfbf;
  cursor: not-allowed;
}

.fdl-ctx-menu__item--disabled:hover {
  background: transparent;
}

.fdl-ctx-menu__item--divider {
  padding: 0;
  cursor: default;
}

.fdl-ctx-menu__item--divider:hover {
  background: transparent;
}

.fdl-ctx-menu__icon {
  font-size: 14px;
  flex-shrink: 0;
}

.fdl-ctx-menu__label {
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.fdl-ctx-menu__divider {
  height: 1px;
  background: #f0f0f0;
  margin: 4px 0;
}
</style>
