  /**
   * 获取所有模式的完整权限配置（已合并默认值）
   *
   * 用途：
   * - ModeSelection 组件打开弹框时使用
   * - 确保 UI 显示完整的权限配置（所有 checkbox 都有明确的 true/false）
   * - 包括用户扩展的自定义模式
   *
   * @returns 所有模式的完整权限配置
   *
   * @example
   * const allPermissions = designer.getAllPermissions()
   * console.log(allPermissions)
   * // {
   * //   design: { showToolbar: true, canDrag: true, ... },
   * //   readonly: { showToolbar: true, canDrag: false, ... },
   * //   preview: { showToolbar: false, canDrag: false, ... }
   * // }
   */
  public getAllPermissions(): Record<string, ModeCapabilities> {
    try {
      const normalized: Record<string, ModeCapabilities> = {}

      // 获取所有可用的模式（从内置预设和用户配置中）
      const permissionConfig = this.options.permissionConfig || {}
      const allModes = new Set([
        'design',
        'readonly',
        'preview',
        ...Object.keys(permissionConfig)
      ])

      console.log('[FlowDesigner.getAllPermissions] 所有模式：', Array.from(allModes))
      console.log('[FlowDesigner.getAllPermissions] 用户配置：', permissionConfig)

      // 保存原始模式
      const originalMode = this.mode.getMode()

      // 遍历所有模式，获取完整配置
      allModes.forEach(mode => {
        try {
          // 临时切换模式以获取该模式的完整权限
          this.mode.setMode(mode)
          const capabilities = this.mode.getCapabilities()

          console.log(`[FlowDesigner.getAllPermissions] 模式 ${mode} 权限:`, capabilities)

          // 验证返回的数据是否有效
          if (capabilities && typeof capabilities === 'object' && Object.keys(capabilities).length > 0) {
            normalized[mode] = capabilities
          } else {
            console.warn(`[FlowDesigner.getAllPermissions] 模式 ${mode} 获取失败`)
          }
        } catch (error) {
          console.error(`[FlowDesigner.getAllPermissions] 获取模式 ${mode} 失败:`, error)
        }
      })

      // 恢复原始模式
      this.mode.setMode(originalMode)

      console.log('[FlowDesigner.getAllPermissions] 最终返回：', normalized)
      return normalized

    } catch (error) {
      console.error('[FlowDesigner.getAllPermissions] 错误：', error)
      return {}
    }
  }

