  private updateGraphInteraction(): void {
    const caps = this.mode.getCapabilities()

    // 1. 更新直接拖拽控制（非选中状态下拖动节点）
    this.graph.options.interacting = {
      nodeMovable: caps.canDrag,
      edgeMovable: false,
      edgeLabelMovable: false,
      magnetConnectable: caps.canConnect,
      arrowheadMovable: false,
      vertexMovable: false,
      vertexAddable: false,
      vertexDeletable: false,
    }

    // 2. 重新挂载 Selection 插件（解决权限动态更新问题）
    // 卸载旧的 Selection 插件
    this.graph.disposePlugins('selection')

    // 重新挂载 Selection 插件，应用最新权限配置
    this.graph.use(
      new Selection({
        enabled: true,
        multiple: caps.canMultipleSelect,
        rubberband: caps.canMultipleSelect,
        movable: caps.canDrag,
        showNodeSelectionBox: true,
        showEdgeSelectionBox: false,
        multipleSelectionModifiers: ['ctrl', 'meta'],
        // 根据权限过滤可选中的元素（重要：防止在禁止选中的模式下仍然能选中）
        filter: (cell) => {
          if (cell.isNode()) return caps.canSelectNode
          if (cell.isEdge()) return caps.canSelectEdge
          return true
        },
      })
    )

    // 3. 重新应用 interaction 配置，让 rubberband/multiple 与最新权限做 AND
    this.config.applyToGraph(this.graph, this.transform, caps)
  }

  /**
   * 动态更新权限配置并立即同步到 X6 Graph
   *
   * 支持两种调用方式：
   * 1. 直接传入完整的权限配置映射：updatePermissions({ design: {...}, readonly: {...} })
   * 2. 传入 options 对象：updatePermissions({ permissionConfig: {...}, permissions: {...} })
   *
   * @param configOrOptions - 权限配置或选项对象
   *
   * @example
   * // 方式1：直接传入配置（推荐，用于 ModeSelection）
   * designer.updatePermissions({
   *   design: { canDrag: true },
   *   readonly: { canDrag: false }
   * })
   *
   * // 方式2：传入 options 对象
   * designer.updatePermissions({
   *   permissionConfig: { design: { canDrag: true } }
   * })
   */
  public updatePermissions(
    configOrOptions: Record<string, Partial<ModeCapabilities>> | {
      permissionConfig?: PermissionOptions['permissionConfig']
      permissions?: PermissionOptions['permissions']
      getPermissions?: PermissionOptions['getPermissions']
    }
  ): void {
    // 判断是直接传入配置还是 options 对象
    // 如果包含 permissionConfig/permissions/getPermissions 任一属性，则视为 options
    const isOptionsObject =
      'permissionConfig' in configOrOptions ||
      'permissions' in configOrOptions ||
      'getPermissions' in configOrOptions

    if (isOptionsObject) {
      // 方式2：options 对象
      this.mode.updatePermissionOptions(configOrOptions as {
        permissionConfig?: PermissionOptions['permissionConfig']
        permissions?: PermissionOptions['permissions']
        getPermissions?: PermissionOptions['getPermissions']
      })
    } else {
      // 方式1：直接传入配置
      this.mode.updatePermissionOptions({
        permissionConfig: configOrOptions as Record<string, Partial<ModeCapabilities>>
      })
    }

    // 重新应用权限到 Graph 交互配置
    this.updateGraphInteraction()
  }

